var e=[{id:`L2_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`앗, 강아지다!`,JPN:`あっ、ワンちゃんだ！`,ENG:`Oh, a puppy!`,TWN:`啊，是小狗！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`이리 온-`,JPN:`こっちにおい……`,ENG:`Come here.`,TWN:`過來這邊～`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`와, 엄청 순하다. 사람이 안 무서운가 봐.`,JPN:`わぁ、いい子だね？　人が怖くないみたい。`,ENG:`Wow, she's so nice. She's not even scared.`,TWN:`哇，好乖喔，一點都不害怕人呢。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`하림아, 너도 만져봐! 엄청 부드러워.`,JPN:`ウサギも触ってみれば？　すごく柔らかいよ。`,ENG:`Harim, you should come pet it too! Her fur is really soft.`,TWN:`夏琳，妳也摸摸看！好柔軟啊。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`나, 난 됐어. 들짐승 만지면 병 옮는대.`,JPN:`ぼ、僕はいい。
野生の動物に触ると病気が移るんだって。`,ENG:`I-I'm fine. They say you can get diseases from touching wild animals.`,TWN:`我、我就算了。人家說摸野狗會生病的。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PUPPY_EXTRA_NULL_NULL`,text:{KOREA:`멍!`,JPN:`ワン！`,ENG:`Woof!`,TWN:`汪！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`이힉-!`,JPN:`うわぁー！`,ENG:`Ack!`,TWN:`咿！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`......하림아. 방금 너 날아오르는 줄 알았어.`,JPN:`……ウサギ、いま一瞬空飛んだよね？`,ENG:`Harim. I thought you were going to fly away.`,TWN:`……夏琳，剛才我還以為妳飛了起來。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`너, 설마 이런 작은 강아지가 무서운 거야?`,JPN:`まさか、こんな子犬が怖いの？`,ENG:`Are you seriously afraid of this little puppy?`,TWN:`妳，該不會害怕這樣的小狗吧？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`무, 무서운 게 아니라 더러운 거라니까? 너도 만지지 마.`,JPN:`こ、怖いんじゃなくて
汚いから。あなたも触らない方がいいよ。`,ENG:`I-I'm not scared. It's just dirty. You shouldn't touch it either.`,TWN:`我、我才不是害怕，只是覺得很髒而已，妳也別摸了。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`아, 잠깐만 기다려줘.`,JPN:`あ、ちょっと待ってて。`,ENG:`Oh, give me a second.`,TWN:`啊，稍等一下。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`우리 집에 저번에 이웃집 강아지 맡았을 때 받은 사료가 남아있을 거야.`,JPN:`この前、お隣のワンちゃんを預かったときの餌が残ってたと思う！`,ENG:`There should be some leftover pet food at my house from when we took care of our neighbor's dog.`,TWN:`上次幫忙照顧鄰居的小狗時，我家裡還剩下一些飼料。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`나, 나도 갈래!`,JPN:`ぼ、僕も行く！`,ENG:`I-I want to go too!`,TWN:`我、我也要去！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CHILD_EXTRA_NULL_NULL`,text:{KOREA:`에이, 그 사이에 가 버리면 아쉽잖아. 네가 놀아 주고 있어 줘.`,JPN:`ダメだよ、その間にいなくなったら
どうするの？　その子と遊んであげて！`,ENG:`Aw, but what if the puppy leaves? You stay behind and keep her entertained.`,TWN:`不，這段時間妳也跟我去就太可惜了，妳就陪牠玩吧。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`......윽.`,JPN:`……うっ。`,ENG:`Ugh.`,TWN:`……呃。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PUPPY_EXTRA_NULL_NULL`,text:{KOREA:`멍?`,JPN:`ワン？`,ENG:`Woof?`,TWN:`汪？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HARIM_KID_NULL_NULL`,text:{KOREA:`......오, 오지 마.`,JPN:`……こ、来ないで。`,ENG:`D-don't come close.`,TWN:`……別、別過來。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`PUPPY_EXTRA_NULL_NULL`,text:{KOREA:`멍멍-`,JPN:`ワンワンー。`,ENG:`Woof, woof!`,TWN:`汪汪！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HARIM_KID_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};